#!/bin/bash
duckdb -c "SELECT column1 as object_id, 'missing in: ' || string_agg(provider, ', ') FROM (SELECT column1, 'satellite_A' as provider FROM read_csv_auto('providers/*/observations.csv', header=False) WHERE column1 NOT IN (SELECT column1 FROM read_csv_auto('providers/satellite_A/observations.csv', header=False)) UNION SELECT column1, 'satellite_B' FROM read_csv_auto('providers/*/observations.csv', header=False) WHERE column1 NOT IN (SELECT column1 FROM read_csv_auto('providers/satellite_B/observations.csv', header=False)) UNION SELECT column1, 'ground_station' FROM read_csv_auto('providers/*/observations.csv', header=False) WHERE column1 NOT IN (SELECT column1 FROM read_csv_auto('providers/ground_station/observations.csv', header=False))) GROUP BY 1;"
